import { useRef } from 'react';
import { useIntl } from 'react-intl';

import { OverlayStackingProvider } from '../../../../../../core/providers/OverlayStackingProvider.js';
import { Tooltip } from '../../../../../../overlays/tooltip/Tooltip.js';
import { DEFAULT_TRUNCATION_MODE } from '../../../../constants.js';
import { useTruncationDetector } from '../../../../hooks/useTruncationDetector.js';
import { ChartTextEllipsis } from '../../../text-ellipsis/ChartTextEllipsis.js';
import { PrimaryAtom } from '../../../tooltip-atoms/components/PrimaryAtom.js';
import { SecondaryAtom } from '../../../tooltip-atoms/components/SecondaryAtom.js';
import type { TooltipTextProps } from '../../types/tooltip.js';

export const TooltipText = (props: TooltipTextProps) => {
  const {
    children: text,
    variant = 'primary',
    truncationMode = DEFAULT_TRUNCATION_MODE,
    ...rest
  } = props;

  const textRef = useRef<HTMLSpanElement>(null);
  const isTruncated = useTruncationDetector(textRef, text);
  const intl = useIntl();

  return (
    <OverlayStackingProvider>
      <Tooltip text={text} disabled={!isTruncated}>
        {variant === 'primary' ? (
          <PrimaryAtom {...rest}>
            <ChartTextEllipsis
              ref={textRef}
              truncationMode={truncationMode}
              aria-label={intl.formatMessage({
                defaultMessage: 'Primary series name',
                id: 'OwC/n+tx4kFWA3l3',
              })}
            >
              {text}
            </ChartTextEllipsis>
          </PrimaryAtom>
        ) : (
          <SecondaryAtom {...rest}>
            <ChartTextEllipsis
              ref={textRef}
              truncationMode={truncationMode}
              aria-label={intl.formatMessage({
                defaultMessage: 'Secondary series name',
                id: 'QbeiZKf6kqgyTp3m',
              })}
            >
              {text}
            </ChartTextEllipsis>
          </SecondaryAtom>
        )}
      </Tooltip>
    </OverlayStackingProvider>
  );
};

TooltipText['displayName'] = 'TooltipText';
